import java.util.Scanner;

public class LoanCheck {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        System.out.print("Annual income: ");
        double income = sc.nextDouble();
        System.out.print("Age: ");
        int age = sc.nextInt();
        System.out.print("Credit score: ");
        int credit = sc.nextInt();
        System.out.print("Existing loans: ");
        double loans = sc.nextDouble();

        boolean incomeOk = income >= 300000;
        boolean ageOk = age >= 21 && age <= 60;
        boolean creditOk = credit >= 700;
        boolean loansOk = loans <= 500000;

        if (incomeOk && ageOk && creditOk && loansOk) {
            System.out.println("APPROVED");
        } else {
            System.out.println("DECLINED");
            if (!incomeOk) System.out.println("- Income below \u20B93,00,000");
            if (!ageOk)    System.out.println("- Age outside 21-60");
            if (!creditOk) System.out.println("- Credit score below 700");
            if (!loansOk)  System.out.println("- Existing loans above \u20B95,00,000");
        }

        sc.close();
    }
}
